fn find_python_dir() -> Option<PathBuf> {
        std::env::current_exe().ok().and_then(|exe| {
            // .parent() = target/debug|release, .parent() = target, .parent() = workspace root
            exe.parent()
                .and_then(|p| p.parent())
                .and_then(|p| p.parent())
                .map(|root| root.join("python"))
        }).filter(|p| p.exists())
    }
